solutions.javascript:
// Solution
class Container<T> {
  private items: T[];

  constructor() {
    this.items = [];
  }

  add(item: T) {
    this.items.push(item);
  }

  add(items: T[]): void {
    items.forEach((item: T) => this.items.push(item));
  }
}

solutions.python:
class Container(T):
  def __init__(self) -> None:
    self.items: T[] = []

  def add(self, item: T) -> None:
    self.items.append(item)

  def add(self, items: T[]) -> None:
    for item in items:
      self.items.append(item)
